import java.io.IOException;
import java.util.StringTokenizer;

import org.apache.hadoop.conf.Configuration;
import org.apache.hadoop.fs.Path;
import org.apache.hadoop.io.IntWritable;
import org.apache.hadoop.io.Text;
import org.apache.hadoop.mapreduce.Job;
import org.apache.hadoop.mapreduce.Mapper;
import org.apache.hadoop.mapreduce.Reducer;
import org.apache.hadoop.mapreduce.lib.input.FileInputFormat;
import org.apache.hadoop.mapreduce.lib.output.FileOutputFormat;

/**
 * Hadoop MapReduce Word Count Application
 * Demonstrates distributed processing of large text files
 */
public class WordCount {

    // ====== MAPPER CLASS ======
    /**
     * Mapper: Takes input (filename, text) and emits (word, 1) pairs
     * Runs on DataNodes for data locality - processes data where it's stored
     */
    public static class TokenizerMapper 
            extends Mapper<Object, Text, Text, IntWritable> {

        private final static IntWritable one = new IntWritable(1);
        private Text word = new Text();

        /**
         * Map function: Tokenize input text and emit word counts
         * @param key: Byte offset of the line in the file
         * @param value: One line of text
         * @param context: Output collector for (word, 1) pairs
         */
        @Override
        public void map(Object key, Text value, Context context)
                throws IOException, InterruptedException {

            // Tokenize the line into words
            StringTokenizer itr = new StringTokenizer(value.toString());

            while (itr.hasMoreTokens()) {
                word.set(itr.nextToken());
                // Emit (word, 1) - this goes to the Shuffle phase
                context.write(word, one);
            }
        }
    }

    // ====== REDUCER CLASS ======
    /**
     * Reducer: Aggregates all counts for each word
     * Input: (word, [1, 1, 1, ...]) - list of ones from all mappers
     * Output: (word, total_count)
     */
    public static class IntSumReducer 
            extends Reducer<Text, IntWritable, Text, IntWritable> {

        private IntWritable result = new IntWritable();

        /**
         * Reduce function: Sum all counts for a word
         * @param key: The word
         * @param values: Iterator of 1s from all mappers
         * @param context: Final output (word, total_count)
         */
        @Override
        public void reduce(Text key, Iterable<IntWritable> values,
                Context context) throws IOException, InterruptedException {

            int sum = 0;
            // Sum all the counts
            for (IntWritable val : values) {
                sum += val.get();
            }
            result.set(sum);
            context.write(key, result);
        }
    }

    // ====== MAIN JOB CONFIGURATION ======
    /**
     * Main method: Configures and submits the MapReduce job
     */
    public static void main(String[] args) throws Exception {
        // Check command line arguments
        if (args.length != 2) {
            System.err.println("Usage: wordcount <input path> <output path>");
            System.exit(-1);
        }

        // Get default configuration
        Configuration conf = new Configuration();

        // Create and configure the job
        Job job = Job.getInstance(conf, "word count");
        job.setJarByClass(WordCount.class);

        // Set mapper class
        job.setMapperClass(TokenizerMapper.class);

        // Set combiner class (mini-reducer on mapper node for optimization)
        job.setCombinerClass(IntSumReducer.class);

        // Set reducer class
        job.setReducerClass(IntSumReducer.class);

        // Set output key type (Text for words)
        job.setOutputKeyClass(Text.class);

        // Set output value type (IntWritable for counts)
        job.setOutputValueClass(IntWritable.class);

        // Set input path from command line
        FileInputFormat.addInputPath(job, new Path(args[0]));

        // Set output path from command line
        FileOutputFormat.setOutputPath(job, new Path(args[1]));

        // Wait for job completion and exit with appropriate code
        System.exit(job.waitForCompletion(true) ? 0 : 1);
    }
}

// ====== COMPILE AND RUN COMMANDS ======
/*
COMPILE:
$ export HADOOP_CLASSPATH=$(hadoop classpath)
$ javac -cp $HADOOP_CLASSPATH WordCount.java
$ jar cf wc.jar WordCount*.class

RUN:
hadoop jar wc.jar WordCount /input/text /output/wordcount

HADOOP STREAMING (for Python mappers):
hadoop jar $HADOOP_HOME/share/hadoop/tools/lib/hadoop-streaming.jar \
    -input /input/text \
    -output /output/wordcount \
    -mapper /path/to/mapper.py \
    -reducer /path/to/reducer.py
*/
